SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, TRY_CAST(left(CAST("FLT_DATE" AS VARCHAR), 10) AS DATE) AS date, NULLIF("APT_ICAO", '') AS apt_icao, NULLIF("APT_NAME", '') AS apt_name, NULLIF("STATE_NAME", '') AS state_name, TRY_CAST("FLT_DEP_1" AS DOUBLE) AS flt_dep_1, TRY_CAST("FLT_DEP_IFR_2" AS DOUBLE) AS flt_dep_ifr_2, TRY_CAST("DLY_ATC_PRE_2" AS DOUBLE) AS dly_atc_pre_2, TRY_CAST("FLT_DEP_3" AS DOUBLE) AS flt_dep_3, TRY_CAST("DLY_ATC_PRE_3" AS DOUBLE) AS dly_atc_pre_3 FROM "eurocontrol-atc-pre-departure-delays") WHERE date IS NOT NULL
